function removeLiquidity(address _tokenAddress, uint256 _amount)
    public
    onlyRole(ADMIN_ROLE)
    nonReentrant
    whenNotPaused
    isTokenSupported(_tokenAddress)
{
    Pool storage pool = liquidityPool[_tokenAddress];
    require(pool.balance >= _amount, InsufficientLiquidity());
    pool.balance -= _amount;

    tokenTransfer(_tokenAddress, _amount, msg.sender);
